class Solution {
public:
    int minAddToMakeValid(string s) {
        int open = 0, close = 0;
        for (char c : s) {
            if (c == '(') open++;
            else close++;
            if (close > open) open++;
        }
        return open + close - 2 * open;
    }
};
```
